{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Analog Matrix Control Suite (GFX Edition)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab High-visibility interface for Analog Molecule plugin parameters.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Manual Line-Break Help & Settings\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Refined UI labels and a robust multiline help system with manual formatting.\sa180\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Sets all sends on selected tracks to Post-Fader (Post-FX) mode.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Sets all sends on selected tracks to Pre-Fader (Post-FX) mode and reports the number of sends changed.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Copies the focused FX or container from one track to selected tracks at a specified position.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Imports CUE and BWF metadata cues from selected items as project markers.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 TLC Dashboard\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Central hub for session templates, recent projects and studio tools. Includes quick actions, color\u8209 ?coded sessions and auto-start options.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Generates reports on FX chains per track and overall plugin frequency. Saves Tracks_FX.txt and FX_Usage.txt in the project directory.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Mutes the "Mixbus" track and selects tracks with "Print" in their name.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Forces the mixer window to a maximized state. Requires JS_API.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Opens the floating window for the plugin in the 3rd slot of the Monitor FX chain.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Cycles through all plugins in the Monitor FX chain, showing one at a time.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Analyzes audio items to find True Peaks, accounting for volume and envelopes. Creates a report track with markers at peak positions.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Renames tracks named "Stereo Out" to the name of the first track in the project.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Mixbus Selection\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Clears current track selections and selects the track named "Mixbus".\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Name Matching\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Uses case-insensitive comparison to find the mixbus.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Navigation\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Useful for navigating to the main output stage of a project.\sa180\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Track Selection\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Scans tracks in the project to select those containing at least one mono audio item.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Source Detection\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Checks the media source channel count (1 channel) to determine if a track is mono.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Content Filtering\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Ignores MIDI items and empty tracks to focus on mono audio.\sa180\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Stereo Identification\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Scans tracks in the project to identify those containing at least one stereo audio item (2 channels).\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Selection\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Appends identified stereo tracks to the existing selection.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Validation\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Checks the channel count of the active take while filtering out MIDI.\sa180\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Track Selection\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Identifies and selects tracks containing the word "Print" in their name.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Selection State\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Resets the project's selection state before performing the search.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Processing Preparation\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Useful for stem exports or processing for projects with "Print" track naming.\sa180\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Setlist Loading\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Manages project files (.RPP) into project tabs for live sets or sessions.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Asynchronous Engine\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Handles project loading without freezing the REAPER interface.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Drag-and-Drop\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Add songs by dragging .RPP files directly onto the interface.\sa180\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Plugin renaming and database tool\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Tool for plugin naming and database management.\sa180\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Time Range Creation\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Sets the project's time selection between two markers named "=START" and "=END".\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Marker Detection\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Scans project markers while ignoring regions for selection boundaries.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Feedback\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Provides a message box if markers are missing.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Marker Order\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Adjusts if markers are placed in reverse order.\sa180\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Mixer Centering\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Centers the selected track in the Mixer Control Panel (MCP) using a visual offset.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Background Monitoring\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Runs in the background and monitors track selection changes.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Offset\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Uses a customizable offset to position the selected track in the mixer view.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Visual Context\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Calculates the scroll position based on the selection.\sa180\par}
}
